private static async buildCredentials(
  credsManager: AwsCredentialsManager,
  region: string,
  integration?: AwsCodeCommitIntegration,
): Promise<AwsCredentialIdentityProvider> {
  // Fall back to the default credential chain if neither account ID
  // nor explicit credentials are provided
  if (!integration) {
    return (await credsManager.getCredentialProvider()).sdkCredentialProvider;
  }

  const accessKeyId = integration.config.accessKeyId;
  const secretAccessKey = integration.config.secretAccessKey;
  let explicitCredentials: AwsCredentialIdentityProvider;
  if (accessKeyId && secretAccessKey) {
    explicitCredentials = AwsCodeCommitUrlReader.buildStaticCredentials(
      accessKeyId,
      secretAccessKey,
    );
  } else {
    explicitCredentials = (await credsManager.getCredentialProvider())
      .sdkCredentialProvider;
  }

  const roleArn = integration.config.roleArn;
  if (roleArn) {
    return fromTemporaryCredentials({
      masterCredentials: explicitCredentials,
      params: {
        RoleSessionName: 'backstage-aws-code-commit-url-reader',
        RoleArn: roleArn,
        ExternalId: integration.config.externalId,
      },
      clientConfig: { region },
    });
  }

  return explicitCredentials;
}

export async function createWorkspaceLinkingPlugins(
  bundler: typeof rspack,
  workspace: string,
) {
  const { packages: linkedPackages, root: linkedRoot } = await getPackages(
    workspace,
  );

  // Matches all packages in the linked workspaces, as well as sub-path exports from them
  const replacementRegex = new RegExp(
    `^(?:${linkedPackages
      .map(pkg => pkg.packageJson.name)
      .join('|')})(?:/.*)?$`,
  );

  return [
    // Any imports of a package that is present in the linked workspace will
    // be redirected to be resolved within the context of the linked workspace
    new bundler.NormalModuleReplacementPlugin(replacementRegex, resource => {
      resource.context = linkedRoot.dir;
    }),
    // react and react-dom are always resolved from the target directory
    // Note: this often requires that the linked and target workspace use the same versions of React
    new bundler.NormalModuleReplacementPlugin(
      /^react(?:-router)?(?:-dom)?$/,
      resource => {
        if (!relativePath(linkedRoot.dir, resource.context).startsWith('..')) {
          resource.context = targetPaths.dir;
        }
      },
    ),
  ];
}

static fromConfig(config: Config): DefaultAwsCredentialsManager {
  const awsConfig = config.has('aws')
    ? readAwsIntegrationConfig(config.getConfig('aws'))
    : {
        accounts: [],
        mainAccount: {},
        accountDefaults: {},
      };

  const mainAccountSdkCredProvider = getMainAccountSdkCredentialProvider(
    awsConfig.mainAccount,
  );
  const mainAccountCredProvider: AwsCredentialProvider = {
    stsRegion: awsConfig.mainAccount.region,
    sdkCredentialProvider: mainAccountSdkCredProvider,
  };

  const accountCredProviders = new Map<string, AwsCredentialProvider>();
  for (const accountConfig of awsConfig.accounts) {
    const sdkCredentialProvider = getSdkCredentialProvider(
      accountConfig,
      mainAccountSdkCredProvider,
    );
    accountCredProviders.set(accountConfig.accountId, {
      accountId: accountConfig.accountId,
      stsRegion: accountConfig.region,
      sdkCredentialProvider,
    });
  }

  return new DefaultAwsCredentialsManager(
    accountCredProviders,
    awsConfig.accountDefaults,
    mainAccountCredProvider,
  );
}

register({ registerInit }) {
  registerInit({
    deps: {
      scaffolder: scaffolderActionsExtensionPoint,
      autocomplete: scaffolderAutocompleteExtensionPoint,
      config: coreServices.rootConfig,
    },
    async init({ scaffolder, autocomplete, config }) {
      const integrations = ScmIntegrations.fromConfig(config);

      scaffolder.addActions(
        createGitlabGroupEnsureExistsAction({ integrations }),
        createGitlabGroupAccessAction({ integrations }),
        createGitlabProjectMigrateAction({ integrations }),
        createGitlabIssueAction({ integrations }),
        createGitlabProjectAccessTokenAction({ integrations }),
        createGitlabProjectDeployTokenAction({ integrations }),
        createGitlabProjectVariableAction({ integrations }),
        createGitlabRepoPushAction({ integrations }),
        createGitlabUserInfoAction({ integrations }),
        editGitlabIssueAction({ integrations }),
        createPublishGitlabAction({ config, integrations }),
        createPublishGitlabMergeRequestAction({ integrations }),
        createTriggerGitlabPipelineAction({ integrations }),
      );

      autocomplete.addAutocompleteProvider({
        id: 'gitlab',
        handler: createHandleAutocompleteRequest({ integrations }),
      });
    },
  });
}

function write_hook(chunk, encoding, callback) {
  // If res.end has already been called, do nothing.
  if (res.finished) {
    return false;
  }

  // Do not mung on errors
  if (!mungError && res.statusCode >= 400) {
    return original.apply(res, arguments);
  }

  try {
    let modifiedChunk = fn(
      chunk,
      // Since `encoding` is an optional argument to `res.write`,
      // make sure it is a string and not actually the callback.
      typeof encoding === 'string' ? encoding : null,
      req,
      res,
    );

    // res.finished is set to `true` once res.end has been called.
    // If it is called in the mung function, stop execution here.
    if (res.finished) {
      return false;
    }

    // If no returned value from fn, then set it back to the original value
    if (modifiedChunk === undefined) {
      modifiedChunk = chunk;
    }

    return original.call(res, modifiedChunk, encoding, callback);
  } catch (err) {
    return mung.onError(err, req, res, next);
  }
}

function createClientErrorConstructor (HttpError, name, code) {
  var className = toClassName(name)

  function ClientError (message) {
    // create the error object
    var msg = message != null ? message : statuses.message[code]
    var err = new Error(msg)

    // capture a stack trace to the construction point
    Error.captureStackTrace(err, ClientError)

    // adjust the [[Prototype]]
    setPrototypeOf(err, ClientError.prototype)

    // redefine the error message
    Object.defineProperty(err, 'message', {
      enumerable: true,
      configurable: true,
      value: msg,
      writable: true
    })

    // redefine the error name
    Object.defineProperty(err, 'name', {
      enumerable: false,
      configurable: true,
      value: className,
      writable: true
    })

    return err
  }

  inherits(ClientError, HttpError)
  nameFunc(ClientError, className)

  ClientError.prototype.status = code
  ClientError.prototype.statusCode = code
  ClientError.prototype.expose = true

  return ClientError
}

